  ('bbbbbbbb-bbbb-4bbb-8bbb-000000000001', 'anua-heartleaf-77-toner', 'Anua Heartleaf 77% Soothing Toner', 'Heartleaf water base for redness-prone, dehydrated skin.', 'A bestselling calming toner with 77% heartleaf extract to help balance oil and water while comforting sensitive skin.', 24900, 28900, 'UV-ANUA-TON-250', 48, 8, 'https://images.unsplash.com/photo-1617897903246-7192428e0560?auto=format&fit=crop&w=900&q=80', ARRAY['https://images.unsplash.com/photo-1571875257727-256c39da42af?auto=format&fit=crop&w=900&q=80','https://images.unsplash.com/photo-1556228720-195a672e8a03?auto=format&fit=crop&w=900&q=80']::text[], 'aaaaaaaa-aaaa-4aaa-8aaa-000000000001', 'Houttuynia cordata extract, panthenol, hyaluronic acid.', true, true),
  ('bbbbbbbb-bbbb-4bbb-8bbb-000000000002', 'cosrx-advanced-snail-96-mucin-power-essence', 'COSRX Advanced Snail 96 Mucin Power Essence', 'Iconic snail essence for bounce, repair, and dewy glow.', 'Lightweight essence with 96% snail secretion filtrate to support elasticity and a smooth, reflective finish without heaviness.', 22900, null, 'UV-COSRX-SNAIL-100', 120, 10, 'https://images.unsplash.com/photo-1620916566398-39f1143ab7be?auto=format&fit=crop&w=900&q=80', ARRAY['https://images.unsplash.com/photo-1598440947619-c3f3409e0fd4?auto=format&fit=crop&w=900&q=80']::text[], 'aaaaaaaa-aaaa-4aaa-8aaa-000000000002', 'Snail secretion filtrate, sodium hyaluronate, panthenol.', true, true),
  ('bbbbbbbb-bbbb-4bbb-8bbb-000000000003', 'medicube-collagen-jelly-cream', 'Medicube Collagen Jelly Cream', 'Bouncy jelly cream with a collagen-supporting feel.', 'A cushiony jelly moisturizer that melts into skin for plump, elastic-looking radiance.', 32000, 36000, 'UV-MED-JELLY-50', 6, 8, 'https://images.unsplash.com/photo-1570172619644-dfd03ed5d881?auto=format&fit=crop&w=900&q=80', ARRAY['https://images.unsplash.com/photo-1612817288484-6f916006741a?auto=format&fit=crop&w=900&q=80']::text[], 'aaaaaaaa-aaaa-4aaa-8aaa-000000000003', 'Collagen, peptides, ceramide NP, adenosine.', false, true),
  ('bbbbbbbb-bbbb-4bbb-8bbb-000000000004', 'dr-althea-345-relief-cream', 'Dr.Althea 345 Relief Cream', 'Barrier cream loved for post-treatment comfort.', 'Rich yet breathable relief cream formulated to cocoon compromised skin with multi-layer moisture and a satin-soft finish.', 28900, null, 'UV-DA-345-50', 34, 6, 'https://images.unsplash.com/photo-1596755094514-f87e34085b87?auto=format&fit=crop&w=900&q=80', ARRAY['https://images.unsplash.com/photo-1556228578-0d85b1a4d571?auto=format&fit=crop&w=900&q=80']::text[], 'aaaaaaaa-aaaa-4aaa-8aaa-000000000003', 'Ceramides, panthenol, centella asiatica extract.', true, true),
  ('bbbbbbbb-bbbb-4bbb-8bbb-000000000005', 'skin1004-madagascar-centella-ampoule', 'SKIN1004 Madagascar Centella Ampoule', 'Pure centella ampoule for calm, clear-looking skin.', 'Minimalist ampoule starring centella asiatica from Madagascar.', 19900, 22000, 'UV-SK1-CEN-100', 72, 10, 'https://images.unsplash.com/photo-1608248543803-ba4f8c70ae0b?auto=format&fit=crop&w=900&q=80', ARRAY['https://images.unsplash.com/photo-1522335789203-aabd1fc54bc9?auto=format&fit=crop&w=900&q=80']::text[], 'aaaaaaaa-aaaa-4aaa-8aaa-000000000002', 'Centella asiatica extract (100%).', false, true),
  ('bbbbbbbb-bbbb-4bbb-8bbb-000000000006', 'beauty-of-joseon-relief-sun-rice-probiotics', 'Beauty of Joseon Relief Sun : Rice + Probiotics', 'Chemical sunscreen with a skin-like, elegant finish.', 'Silky relief sunscreen infused with rice and grain probiotics extracts for comfortable daily wear under makeup.', 18900, null, 'UV-BOJ-SUN-50', 90, 12, 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?auto=format&fit=crop&w=900&q=80', ARRAY['https://images.unsplash.com/photo-1522337360788-8b13dee7a37e?auto=format&fit=crop&w=900&q=80']::text[], 'aaaaaaaa-aaaa-4aaa-8aaa-000000000004', 'Rice extract, probiotics, niacinamide.', true, true),
  ('bbbbbbbb-bbbb-4bbb-8bbb-000000000007', 'round-lab-birch-juice-moisturizing-sun-cream', 'Round Lab Birch Juice Moisturizing Sun Cream', 'Hydrating SPF with birch sap and a clean skin feel.', 'Moisturizing sun cream beloved for its lightweight texture and birch juice infusion.', 21900, 23900, 'UV-RL-BIRCH-50', 55, 8, 'https://images.unsplash.com/photo-1487412720507-e7ab37603c6f?auto=format&fit=crop&w=900&q=80', ARRAY['https://images.unsplash.com/photo-1515377905705-c4788e51af15?auto=format&fit=crop&w=900&q=80']::text[], 'aaaaaaaa-aaaa-4aaa-8aaa-000000000004', 'Betula platyphylla japonica juice, hyaluronic acid.', false, true),
  ('bbbbbbbb-bbbb-4bbb-8bbb-000000000008', 'torriden-dive-in-serum', 'Torriden DIVE-IN Low Molecule Hyaluronic Acid Serum', '5D hyaluronic complex for deep, lasting hydration.', 'Watery serum that absorbs quickly, leaving a fresh finish and helping skin look dewy without tackiness.', 23900, null, 'UV-TOR-DIVE-50', 64, 8, 'https://images.unsplash.com/photo-1556228578-8c89e33adf19?auto=format&fit=crop&w=900&q=80', ARRAY['https://images.unsplash.com/photo-1617897903246-7192428e0560?auto=format&fit=crop&w=900&q=80']::text[], 'aaaaaaaa-aaaa-4aaa-8aaa-000000000002', 'Multi-weight hyaluronic acid, panthenol, allantoin.', true, true),
  ('bbbbbbbb-bbbb-4bbb-8bbb-000000000009', 'mixsoon-bean-essence', 'Mixsoon Bean Essence', 'Fermented bean essence for refined texture.', 'K-beauty favorite for gentle exfoliation and glow.', 26900, 29900, 'UV-MIX-BEAN-50', 41, 6, 'https://images.unsplash.com/photo-1598440947619-c3f3409e0fd4?auto=format&fit=crop&w=900&q=80', ARRAY['https://images.unsplash.com/photo-1571875257727-256c39da42af?auto=format&fit=crop&w=900&q=80']::text[], 'aaaaaaaa-aaaa-4aaa-8aaa-000000000002', 'Lactobacillus/soybean ferment extract, pomegranate.', false, true),
  ('bbbbbbbb-bbbb-4bbb-8bbb-000000000010', 'laneige-lip-sleeping-mask', 'Laneige Lip Sleeping Mask', 'Overnight lip mask for pillow-soft morning lips.', 'Berry complex and a melting balm texture wrap lips overnight.', 17900, 19900, 'UV-LAN-LIP-20', 102, 15, 'https://images.unsplash.com/photo-1586495777744-4413f21062fa?auto=format&fit=crop&w=900&q=80', ARRAY['https://images.unsplash.com/photo-1522338242992-e1a54906a8da?auto=format&fit=crop&w=900&q=80']::text[], 'aaaaaaaa-aaaa-4aaa-8aaa-000000000005', 'Shea butter, murumuru seed butter, vitamin C derivative.', true, true)
